sql:
SELECT c.county_name
FROM counties c
JOIN (
  SELECT county_id, AVG(average_annual_count) AS avg_annual_count_per_county
  FROM cancer_incidence_rates
  GROUP BY county_id
) AS county_avg ON c.county_id = county_avg.county_id
WHERE county_avg.avg_annual_count_per_county > (
  SELECT AVG(average_annual_count) FROM cancer_incidence_rates
);

SELECT county_name, population_density
FROM counties
ORDER BY population_density DESC;

SELECT c.county_name, cir.age_adjusted_rate
FROM counties c
JOIN cancer_incidence_rates cir ON c.county_id = cir.county_id
WHERE cir.age_adjusted_rate = (
    SELECT MAX(age_adjusted_rate) FROM cancer_incidence_rates
);

external_knowledge:
- "grappling with the tempest" metaphorically refers to dealing with high incidence rates;
- "stormy average" refers to the average annual count of cancer cases being more than 15,000;
- "house a populace exceeding a million souls" means the population of the county is over 1,000,000.
